import{_ as d,o,c as e,a2 as r}from"./chunks/framework.ChW7XBuO.js";const b=JSON.parse('{"title":"已知限制","description":"rolebox 当前版本已知限制 — 角色继承、运行时切换、函数持久化、子代理嵌套深度","frontmatter":{"title":"已知限制","description":"rolebox 当前版本已知限制 — 角色继承、运行时切换、函数持久化、子代理嵌套深度"},"headers":[],"relativePath":"03-Reference/limitations.md","filePath":"03-Reference/limitations.md"}'),a={name:"03-Reference/limitations.md"};function c(s,t,n,h,i,l){return o(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="已知限制" tabindex="-1">已知限制 <a class="header-anchor" href="#已知限制" aria-label="Permalink to &quot;已知限制&quot;">​</a></h1><blockquote><p><strong>相关文档：</strong> <a href="/rolebox-docs/03-Reference/error-handling.html">错误处理</a> — 错误容忍机制 | <a href="/rolebox-docs/03-Reference/dispatch-config.html">调度配置</a> — 调度系统限制与配置 | <a href="/rolebox-docs/03-Reference/hooks.html">Hook 机制</a> — Hook 限制</p></blockquote><p>以下是 rolebox 当前版本（v1.x）的已知功能限制。</p><h2 id="限制一览" tabindex="-1">限制一览 <a class="header-anchor" href="#限制一览" aria-label="Permalink to &quot;限制一览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>限制</th><th>说明</th><th>应对策略</th></tr></thead><tbody><tr><td><strong>无角色继承</strong></td><td>角色之间不支持继承或组合机制，每个角色是独立定义</td><td>通过技能（skills）和引用（references）共享通用配置；利用子代理（subagents）实现功能组合与分层复用</td></tr><tr><td><strong>无运行时角色切换</strong></td><td>会话启动后不能动态切换角色</td><td>预先定义多个子代理在不同工作模式下并行激活；或退出当前会话后以新角色身份重新启动</td></tr><tr><td><strong>函数全会话持久化</strong></td><td>函数在整个会话期间持续激活，暂不支持按消息级别激活/停用</td><td>通过条件函数设计控制函数的生效范围；利用子代理隔离不同阶段所需的函数上下文</td></tr><tr><td><strong>无项目上下文条件函数</strong></td><td>不支持根据项目上下文（如文件类型、目录结构）条件性地激活函数</td><td>在角色初始化阶段手动识别项目类型；为不同项目类型分别定义专用角色并在需要时切换</td></tr><tr><td><strong>子代理嵌套深度上限</strong></td><td>基于文件的递归子代理嵌套最高支持 3 层（父 → 子 → 孙）</td><td>将超出深度的子代理以内联方式声明在父级 role.yaml 的 <code>subagents:</code> 字段中；或将深层子代理扁平化为中间层引用</td></tr><tr><td><strong><code>--</code> 为保留字符</strong></td><td><code>--</code> 在角色 ID 中作为父/子代理分隔符使用，不可用于命名</td><td>使用 <code>-</code> 或 <code>.</code> 等替代分隔符；避免在角色名称中包含 <code>--</code> 组合</td></tr></tbody></table><h2 id="详细说明" tabindex="-1">详细说明 <a class="header-anchor" href="#详细说明" aria-label="Permalink to &quot;详细说明&quot;">​</a></h2><h3 id="无角色继承" tabindex="-1">无角色继承 <a class="header-anchor" href="#无角色继承" aria-label="Permalink to &quot;无角色继承&quot;">​</a></h3><p>每个角色通过 <code>role.yaml</code> 独立定义，不允许从一个角色继承另一个角色的配置（如函数、技能、权限等）。如果多个角色需要共享配置，目前需要通过复制或引用来实现。</p><h3 id="无运行时角色切换" tabindex="-1">无运行时角色切换 <a class="header-anchor" href="#无运行时角色切换" aria-label="Permalink to &quot;无运行时角色切换&quot;">​</a></h3><p>角色在会话初始化时确定，会话运行期间不能切换为其他角色。如果需要在不同角色之间切换工作模式，需要通过子代理调度来实现。</p><h3 id="函数全会话持久化" tabindex="-1">函数全会话持久化 <a class="header-anchor" href="#函数全会话持久化" aria-label="Permalink to &quot;函数全会话持久化&quot;">​</a></h3><p>通过 <code>functions:</code> 字段激活的函数会在整个会话生命周期内保持激活状态。当前不支持按消息粒度动态启用/禁用函数。</p><h3 id="子代理嵌套深度上限" tabindex="-1">子代理嵌套深度上限 <a class="header-anchor" href="#子代理嵌套深度上限" aria-label="Permalink to &quot;子代理嵌套深度上限&quot;">​</a></h3><p>子代理可以通过文件目录进行递归嵌套，但深度上限为 3 层（父 → 子 → 孙 → 曾孙）。超过深度限制的子代理将无法加载。</p><h2 id="各子系统限制" tabindex="-1">各子系统限制 <a class="header-anchor" href="#各子系统限制" aria-label="Permalink to &quot;各子系统限制&quot;">​</a></h2><h3 id="调度系统-dispatch" tabindex="-1">调度系统（Dispatch） <a class="header-anchor" href="#调度系统-dispatch" aria-label="Permalink to &quot;调度系统（Dispatch）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>限制</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><strong>模型并发槽位数</strong></td><td>5</td><td>每个模型密钥（<code>providerID/modelID</code>）的并发执行上限。详见 <code>concurrency.ts:92</code></td></tr><tr><td><strong>保留槽位数</strong></td><td>1</td><td>保留给同步（sync）任务的槽位，后台任务可用上限为 <code>limit - reserved</code>（即 4 个）。详见 <code>concurrency.ts:92</code></td></tr><tr><td><strong>队列最大深度</strong></td><td>10</td><td>等待队列最大长度，超出时返回 <code>QueueFullError</code>。详见 <code>concurrency.ts:92</code></td></tr><tr><td><strong>等待超时</strong></td><td>300 秒（5 分钟）</td><td>队列中等待超时后抛出 <code>WaiterTimeoutError</code>，详见 <code>concurrency.ts:46</code></td></tr><tr><td><strong>子代理嵌套深度</strong></td><td>3 层</td><td>基于文件的子代理递归解析最大深度，超过深度限制的层级被忽略。详见 <code>subagents.ts:237</code></td></tr><tr><td><strong>通知间隔</strong></td><td>2 秒</td><td><code>loop</code> 模块中连续轮次之间的最小延迟。详见 <code>loop/constants.ts:14</code></td></tr></tbody></table><h3 id="记忆系统-memory" tabindex="-1">记忆系统（Memory） <a class="header-anchor" href="#记忆系统-memory" aria-label="Permalink to &quot;记忆系统（Memory）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>限制</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><strong>存储后端</strong></td><td>bun:sqlite（WAL 模式）</td><td>使用 <code>bun:sqlite</code> 作为持久化引擎，启用 WAL 日志模式以提高并发性能。详见 <code>store.ts:28-29</code></td></tr><tr><td><strong>全文检索引擎</strong></td><td>FTS5</td><td>基于 SQLite FTS5 虚拟表，自动同步 <code>title</code>、<code>content</code>、<code>tags</code> 字段。详见 <code>schema.ts:29-34</code></td></tr><tr><td><strong>列表默认上限</strong></td><td>20 条</td><td><code>memory_list</code> 未指定 <code>limit</code> 时最多返回 20 条摘要记录。详见 <code>store.ts:212</code></td></tr><tr><td><strong>搜索默认上限</strong></td><td>10 条</td><td><code>memory_recall</code> 未指定 <code>limit</code> 时最多返回 10 条完整记录。详见 <code>search.ts:42</code></td></tr><tr><td><strong>自动注入上限</strong></td><td>10 条</td><td>会话启动时自动注入系统提示的记忆摘要最大数量。详见 <code>types.ts:13</code></td></tr><tr><td><strong>分类维度</strong></td><td>scope / category / relevance</td><td>支持按作用域、分类和相关性等级过滤；tags 和 source_sessions 以 JSON 数组存储</td></tr></tbody></table><h3 id="图编排系统-graph" tabindex="-1">图编排系统（Graph） <a class="header-anchor" href="#图编排系统-graph" aria-label="Permalink to &quot;图编排系统（Graph）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>限制</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><strong>最大迭代次数（含环图）</strong></td><td>3 次</td><td>当图中检测到环（cycle）且未显式设置 <code>max_iterations</code> 时，默认上限为 3 次。详见 <code>parser.ts:80-81</code></td></tr><tr><td><strong>最大迭代次数（无环图）</strong></td><td>无限制（0）</td><td>无环图默认不限制迭代次数。详见 <code>parser.ts:82-83</code></td></tr><tr><td><strong>用户自定义上限</strong></td><td>由 <code>max_iterations</code> 字段指定</td><td>支持在 graph 配置中显式设置，最小值为 0。详见 <code>parser.ts:44-47</code></td></tr><tr><td><strong>环组独立上限</strong></td><td>通过 termination 配置</td><td>每个 loop group 可单独设置 <code>maxIterations</code>，互不干扰。详见 <code>termination.ts:49</code></td></tr></tbody></table><h3 id="循环执行系统-loop" tabindex="-1">循环执行系统（Loop） <a class="header-anchor" href="#循环执行系统-loop" aria-label="Permalink to &quot;循环执行系统（Loop）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>限制</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><strong>默认迭代次数</strong></td><td>5 次</td><td>未指定 <code>iterations</code> 参数时的默认循环轮次。详见 <code>constants.ts:2</code></td></tr><tr><td><strong>硬上限</strong></td><td>50 次</td><td>单次循环的最大轮次，防止失控执行。详见 <code>constants.ts:5</code></td></tr><tr><td><strong>单轮超时</strong></td><td>900 秒（15 分钟）</td><td>每个 dispatch 轮次的最长等待时间。详见 <code>constants.ts:8</code></td></tr><tr><td><strong>轮次间隔</strong></td><td>2 秒</td><td>连续轮次之间的最小延迟，避免瞬态负载。详见 <code>constants.ts:14</code></td></tr><tr><td><strong>摘要输入上限</strong></td><td>8,000 字符</td><td>每次轮次输出送入摘要器的最大字符数。详见 <code>constants.ts:17</code></td></tr><tr><td><strong>种子字符上限</strong></td><td>8,000 字符</td><td>合并后预置到下一轮次的摘要最大字符数。详见 <code>constants.ts:20</code></td></tr></tbody></table><h3 id="通知系统-notifications" tabindex="-1">通知系统（Notifications） <a class="header-anchor" href="#通知系统-notifications" aria-label="Permalink to &quot;通知系统（Notifications）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>通道</th><th>平台支持</th><th>说明</th></tr></thead><tbody><tr><td><strong>SystemToast</strong></td><td>macOS（terminal-notifier / osascript）、Linux（notify-send）、Windows（PowerShell）</td><td>原生系统通知，各平台依赖不同命令行工具。详见 <code>system-toast.ts</code></td></tr><tr><td><strong>Sound</strong></td><td>macOS（afplay）、Linux（paplay / aplay 回退）、Windows（PowerShell SoundPlayer）</td><td>播放通知音效，需要对应平台音频播放工具。详见 <code>sound.ts</code></td></tr><tr><td><strong>File</strong></td><td>全平台</td><td>以 JSONL 格式追加写入文件，无平台依赖。详见 <code>file.ts</code></td></tr><tr><td><strong>Log</strong></td><td>全平台</td><td>写入结构化日志，无平台依赖。详见 <code>log.ts</code></td></tr><tr><td><strong>Webhook</strong></td><td>全平台（依赖网络可达）</td><td>HTTP POST 到指定 URL，支持自定义请求头和超时（默认 5 秒）。详见 <code>webhook.ts:21</code></td></tr><tr><td><strong>CustomCommand</strong></td><td>全平台</td><td>通过子进程执行自定义命令，参数以环境变量传递，支持 stdin 输入。详见 <code>custom-command.ts</code></td></tr></tbody></table><h3 id="哈希行系统-hashline" tabindex="-1">哈希行系统（Hashline） <a class="header-anchor" href="#哈希行系统-hashline" aria-label="Permalink to &quot;哈希行系统（Hashline）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>限制</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><strong>小文件哈希宽度</strong></td><td>2 位</td><td>文件 ≤ 1000 行时使用，提供 64² = 4,096 个不重复桶。详见 <code>constants.ts:6</code></td></tr><tr><td><strong>中文件哈希宽度</strong></td><td>3 位</td><td>文件 1001–10000 行时使用，提供 64³ = 262,144 个桶。详见 <code>constants.ts:7</code></td></tr><tr><td><strong>大文件哈希宽度</strong></td><td>4 位</td><td>文件 &gt; 10000 行时使用，提供 64⁴ = 16,777,216 个桶。详见 <code>constants.ts:8</code></td></tr><tr><td><strong>环境变量覆盖</strong></td><td><code>ROLEBOX_HASHLINE_WIDTH</code></td><td>可覆盖自动选择的哈希宽度。详见 <code>constants.ts:14</code></td></tr><tr><td><strong>校验正则</strong></td><td><code>/^(\\d+)#([A-Za-z0-9_-]{2,4})$/</code></td><td>哈希引用格式为 <code>行号#哈希</code>，宽度限制 2-4 位。详见 <code>constants.ts:18</code></td></tr><tr><td><strong>模糊搜索窗口</strong></td><td>±10 行</td><td>定位失败时在目标行前后各 10 行内搜索匹配内容。详见 <code>constants.ts:27</code></td></tr></tbody></table><h3 id="平台命令依赖" tabindex="-1">平台命令依赖 <a class="header-anchor" href="#平台命令依赖" aria-label="Permalink to &quot;平台命令依赖&quot;">​</a></h3><p>通知后端通过平台特定的命令行工具发送通知（<code>src/notifications/platform.ts</code>）：</p><table tabindex="0"><thead><tr><th>平台</th><th>SystemToast</th><th>Sound</th></tr></thead><tbody><tr><td>macOS</td><td><code>terminal-notifier</code> 或回退到 <code>osascript</code></td><td><code>afplay</code></td></tr><tr><td>Linux</td><td><code>notify-send</code></td><td><code>paplay</code>，回退到 <code>aplay</code></td></tr><tr><td>Windows</td><td>PowerShell</td><td>PowerShell (<code>SoundPlayer</code>)</td></tr></tbody></table><p>如果目标平台缺少对应的命令行工具，通知静默降级（跳过该通道），不会报错。</p><div class="tip custom-block"><p class="custom-block-title">升级注意事项</p><p>从 v0.12.0 开始，状态存储从 <code>XDG_DATA_HOME</code> 迁移到项目本地 <code>.rolebox/</code> 目录。如果你从更早版本升级，旧的状态文件不会自动迁移。升级后建议先运行 <code>rolebox status</code> 确认所有子系统正常工作。详见<a href="/rolebox-docs/04-Advanced/compatibility.html#v0-12-0-状态存储迁移">兼容性</a>。</p></div><h2 id="外部工具限制" tabindex="-1">外部工具限制 <a class="header-anchor" href="#外部工具限制" aria-label="Permalink to &quot;外部工具限制&quot;">​</a></h2><h3 id="lsp-服务器" tabindex="-1">LSP 服务器 <a class="header-anchor" href="#lsp-服务器" aria-label="Permalink to &quot;LSP 服务器&quot;">​</a></h3><p>rolebox 内置的 LSP 服务器注册表（<code>src/lsp/servers.ts:9-122</code>）支持以下语言，每个语言对应一个外部服务器二进制文件：</p><table tabindex="0"><thead><tr><th>语言</th><th>服务器命令</th><th>根文件标记</th></tr></thead><tbody><tr><td>TypeScript/JavaScript</td><td><code>typescript-language-server</code></td><td><code>tsconfig.json</code> / <code>package.json</code></td></tr><tr><td>Python</td><td><code>pyright-langserver</code></td><td><code>pyproject.toml</code> / <code>setup.py</code></td></tr><tr><td>Go</td><td><code>gopls</code></td><td><code>go.mod</code></td></tr><tr><td>Rust</td><td><code>rust-analyzer</code></td><td><code>Cargo.toml</code></td></tr><tr><td>C/C++</td><td><code>clangd</code></td><td><code>compile_commands.json</code> / <code>CMakeLists.txt</code></td></tr><tr><td>Java</td><td><code>jdtls</code></td><td><code>pom.xml</code> / <code>build.gradle</code></td></tr><tr><td>Ruby</td><td><code>solargraph</code></td><td><code>Gemfile</code></td></tr><tr><td>Bash</td><td><code>bash-language-server</code></td><td>自动检测</td></tr><tr><td>Lua</td><td><code>lua-language-server</code></td><td><code>.luarc.json</code></td></tr><tr><td>Kotlin</td><td><code>kotlin-lsp</code></td><td><code>build.gradle.kts</code></td></tr></tbody></table><p>如果对应服务器的二进制文件未在 <code>PATH</code> 或常见安装路径中找到，该语言的 LSP 功能（诊断、跳转定义、补全等）不可用（<code>src/lsp/servers.ts:226-233</code>）。</p><h3 id="web-搜索与渲染引擎" tabindex="-1">Web 搜索与渲染引擎 <a class="header-anchor" href="#web-搜索与渲染引擎" aria-label="Permalink to &quot;Web 搜索与渲染引擎&quot;">​</a></h3><p>Web 抓取功能依赖可选的浏览器自动化包（<code>src/web/browser-detect.ts:24-46</code>）：</p><ul><li><strong>Playwright</strong>：提供完整的 JS 渲染能力，用于抓取 SPA 和动态网页。</li><li><strong>Crawlee</strong>：提供高级爬取功能。</li></ul><p>如果两者都未安装，web 抓取回退到静态 HTTP 请求模式，无法渲染 JavaScript 生成的内容。</p><h3 id="tui-终端-ui" tabindex="-1">TUI (终端 UI) <a class="header-anchor" href="#tui-终端-ui" aria-label="Permalink to &quot;TUI (终端 UI)&quot;">​</a></h3><p>rolebox 的终端 UI 默认支持 macOS 和 Linux 终端（如 iTerm2、Kitty、Terminator）。Windows 终端兼容性取决于使用的终端模拟器 —— PowerShell 和 Windows Terminal 的基本功能可用，但某些高级渲染特性（如 ANSI 转义序列）可能受限。</p><h2 id="已知边缘情况" tabindex="-1">已知边缘情况 <a class="header-anchor" href="#已知边缘情况" aria-label="Permalink to &quot;已知边缘情况&quot;">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>表现</th><th>相关参考</th></tr></thead><tbody><tr><td><strong>同时启动大量并发任务</strong></td><td>超出 <code>maxConcurrent</code> + <code>maxQueueDepth</code> 的任务返回 <code>QueueFullError</code>，需等待重试</td><td><a href="./dispatch-config.html">调度配置</a></td></tr><tr><td><strong>子代理长时间无响应</strong></td><td>后台任务在 <code>backgroundStaleTimeoutMs</code>（默认 15 分钟）后标记为过期</td><td><a href="./dispatch-config.html">调度配置</a></td></tr><tr><td><strong>队列中任务等待超时</strong></td><td>超过 <code>WAITER_TTL_MS</code>（300 秒）后抛出 <code>WaiterTimeoutError</code></td><td><a href="./dispatch-config.html">调度配置</a>、<a href="./error-handling.html">错误处理</a></td></tr><tr><td><strong>图循环中代理卡住</strong></td><td>达到 <code>max_iterations</code> 或 termination 条件后自动终止</td><td><a href="./error-handling.html">错误处理</a></td></tr><tr><td><strong>预算限制触发后任务取消</strong></td><td>采样间隔 <code>budgetSampleIntervalMs</code> 内可能多消耗一些配额</td><td><a href="./dispatch-config.html">调度配置</a></td></tr><tr><td><strong>扩展模块加载失败</strong></td><td>按模块捕获，记录警告，跳过该扩展，不会影响其他功能</td><td><a href="./extensions.html">扩展机制</a></td></tr><tr><td><strong>Hook 模块加载失败</strong></td><td>记录警告，Hook 被跳过，注册中心存储 <code>null</code> 并继续</td><td><a href="./hooks.html">Hook 机制</a></td></tr><tr><td><strong>插件关闭时 Hook 未释放</strong></td><td><code>onDispose</code> 确保在关闭时清理资源；如果模块未实现 <code>onDispose</code>，资源由进程回收</td><td><a href="./hooks.html">Hook 机制</a></td></tr><tr><td><strong>环境变量插值未解析</strong></td><td>保留原始 <code>{env:VARIABLE_NAME}</code> 文本，不做猜测性替换</td><td><a href="./dispatch-config.html">调度配置</a></td></tr><tr><td><strong>通知通道平台命令缺失</strong></td><td>通道静默降级，无报错；不影响其他功能</td><td>本页上方「平台命令依赖」</td></tr><tr><td><strong>并发策略自定义实现错误</strong></td><td><code>concurrency_policies</code> 扩展加载失败仅影响该策略，回退到默认 <code>ConcurrencyManager</code></td><td><a href="./extensions.html">扩展机制</a></td></tr></tbody></table><h2 id="版本演进路线" tabindex="-1">版本演进路线 <a class="header-anchor" href="#版本演进路线" aria-label="Permalink to &quot;版本演进路线&quot;">​</a></h2><p>以下标记哪些限制属于有意设计约束（短期内不会改变），哪些在规划路线上可能调整。</p><div class="info custom-block"><p class="custom-block-title">设计约束 vs 路线图</p><p>「设计约束」标记的限制基于架构性决策，短期内不会改变——应将其视为系统的稳定边界来规划你的角色设计。「路线图待定」标记的限制在规划中可能调整，但无明确时间表。在受这些限制影响时，可以先采用「应对策略」列中建议的变通方案。</p></div><table tabindex="0"><thead><tr><th>限制</th><th>分类</th><th>说明</th></tr></thead><tbody><tr><td><strong>无角色继承</strong></td><td>设计约束</td><td>角色模型基于组合（composition）而非继承（inheritance），通过子代理和技能复用实现模块化。此为架构性决策，不计划引入继承机制</td></tr><tr><td><strong>无运行时角色切换</strong></td><td>路线图待定</td><td>技术上可通过 <code>dispatch()</code> 间接实现，但原生会话内角色切换需要更复杂的上下文管理机制</td></tr><tr><td><strong>函数全会话持久化</strong></td><td>设计约束</td><td>函数激活模型与函数状态机的生命期绑定，按消息粒度激活/停用将显著增加状态管理复杂度。暂不在路线图中</td></tr><tr><td><strong>无项目上下文条件函数</strong></td><td>路线图待定</td><td>条件函数是需求中高频出现的请求，可能在后续版本中通过扩展 <code>conditions</code> 系统增强</td></tr><tr><td><strong>子代理嵌套深度上限</strong></td><td>路线图待定</td><td>当前 <code>maxDepth: number = 3</code> 在源码中为可调默认值（<code>src/loader/subagents.ts:237</code>），未来可能提高或开放配置</td></tr><tr><td><strong><code>--</code> 为保留字符</strong></td><td>设计约束</td><td>此分隔符是子代理 ID 路由机制的基础，无法变更</td></tr></tbody></table><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="./error-handling.html">错误处理</a> — 了解 rolebox 的错误容忍与降级机制</li></ul>',51)])])}const p=d(a,[["render",c]]);export{b as __pageData,p as default};
